class Solution:
    def memLeak(self, memory1: int, memory2: int) -> List[int]:
        time = 1
        memory1_alloc = 0
        memory2_alloc = 0
        while memory1 > 0 and memory2 > 0:
            if memory1 >= memory2:
                memory1_alloc += time
                memory1 -= time
            else:
                memory2_alloc += time
                memory2 -= time
            time += 1
        return [time, memory1, memory2]

